############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.117) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserFormulaWithUnits.pl", "contextForm.pl", "contextFraction.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Fraction"); $rate = Fraction(random(1,11),12); $speed = FormulaWithUnits("$rate ft"); $initial = random(4,6); $final = random(10,12); $solution = ($final - $initial)/$rate; $time = FormulaWithUnits("$solution yr");
############################################################ # Body ############################################################
BEGIN_PGML You planted a young tree in front of your house, and it was [`[$initial]`] feet tall. Ever since, it has been growing by [`[$speed]`] each year. How many years will it take for the tree to grow to be [$final] feet tall?
[_]{$time}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
